### What was wrong?
A failed call or transaction to a contract will prevent all further calls and transactions from working do to a difference in the state-root.

```python
from solc import (
    compile_source,
)
from web3.providers.eth_tester import (
    EthereumTesterProvider,
)
from web3 import (
    Web3,
)

source = (
    """
    contract Test {
        uint public value = 1;
        function setValue(uint _value) {
            value = _value;
        }
        function willThrow() {
            require(false);
        }
    }
    """
)

# Compile contract source
compilation = compile_source(source)
compilation_info = compilation['<stdin>:Test']

# Get Web3
provider = EthereumTesterProvider()
web3 =  Web3(provider)

# Create and deploy contract
contract = web3.eth.contract(
    abi=compilation_info['abi'],
    bytecode=compilation_info['bin'],
    bytecode_runtime=compilation_info['bin-runtime'],
)
txhash = contract.deploy()
receipt = web3.eth.getTransactionReceipt(txhash)
contract = contract(address=receipt['contractAddress'])

# Call works
contract.call().value()
>> 1

# Transaction works
txhash = contract.transact().setValue(2)
contract.call().value()
>> 2

# Throw an error in the contract
try:
    contract.transact().willThrow()
    # contract.call().willThrow() has the same effect
except:
    pass

# Trying to call or transact again throws this error
# txhash = contract.transact().setValue(3) will throw the same error
contract.call().value()
>> VerificationFailed: ('state_root', b'(\x0e\xf5\xc7\xdc\xeb\xfd\x9a\x03\xe5\xc3c\x99d\xaa\ts\xce\x89\xab\xfdM\x03\xd0,\xe9l\x13\xad\xbc\xff\xd8', '==', b'\x115\xc0!\xfb\xfd\xca\xd4\x00\xb3t)\x9c\xd4\x0cHB\xa0\x90\xc7\xdc\xac\xea\xdfN69\x1cS\xcaZ\x18')

```

### How was it fixed?
I added a `try/except/finally` block to the `estimate_gas` function in `eth_tester/backends/pyethereum/v16/main.py` that will revert to the snapshot on a failed transaction. Does this problem exist in `v20`, and `pyevm`? Maybe a fix needs to be provided for those as well.


